1	export type Cell = readonly [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (isAlive: boolean, neighborCount: number): boolean =>
12	  (isAlive && neighborCount === 2) || neighborCount === 3;
13	
14	export function nextGeneration(cells: readonly Cell[]): Cell[] {
15	  const aliveKeys = new Set(cells.map(cellKey));
16	  const counts = new Map<string, number>();
17	  const cellsByKey = new Map<string, Cell>();
18	
19	  for (const [x, y] of cells) {
20	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
21	      const neighbor: Cell = [x + dx, y + dy];
22	      const key = cellKey(neighbor);
23	      counts.set(key, (counts.get(key) ?? 0) + 1);
24	      cellsByKey.set(key, neighbor);
25	    }
26	  }
27	
28	  return Array.from(counts)
29	    .filter(([key, count]) => survives(aliveKeys.has(key), count))
30	    .map(([key]) => cellsByKey.get(key)!);
31	}
