1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input (no live cells)", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation, 0 neighbors)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block stable (each cell has 3 neighbors, survives)", () => {
15	    const block: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(new Set(result.map(c => `${c[0]},${c[1]}`))).toEqual(
18	      new Set(block.map(c => `${c[0]},${c[1]}`))
19	    );
20	  });
21	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
22	    const vertical: Array<[number, number]> = [[0, 0], [0, 1], [0, 2]];
23	    const result = nextGeneration(vertical);
24	    const resultSet = new Set(result.map(c => `${c[0]},${c[1]}`));
25	    const expectedSet = new Set(["-1,1", "0,1", "1,1"]);
26	    expect(resultSet).toEqual(expectedSet);
27	  });
28	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
29	    // Gen 0: (0,0), (1,0), (0,1) -> dead cell (1,1) has 3 live neighbors and becomes alive
30	    const input: Array<[number, number]> = [[0, 0], [1, 0], [0, 1]];
31	    const result = nextGeneration(input);
32	    const resultSet = new Set(result.map(c => `${c[0]},${c[1]}`));
33	    expect(resultSet.has("1,1")).toBe(true);
34	  });
35	  it("should handle negative coordinates correctly", () => {
36	    // Blinker centered at negative coordinates: vertical at x=-5
37	    const vertical: Array<[number, number]> = [[-5, -1], [-5, 0], [-5, 1]];
38	    const result = nextGeneration(vertical);
39	    const resultSet = new Set(result.map(c => `${c[0]},${c[1]}`));
40	    expect(resultSet).toEqual(new Set(["-6,0", "-5,0", "-4,0"]));
41	  });
42	});
